// ── 5N1K ───────────────────────────────────────────────────────────────────────
const kontrol5N1K = (m) => {
  const t = m.toLowerCase();
  return [
    { soru: "Ne oldu?", kod: "ne", karsilandi: m.trim().length > 10 },
    { soru: "Nerede oldu?", kod: "nerede", karsilandi: /\b(ev|iş|okul|ofis|sokak|yolda|arabada|okulda|işte|evde|dışarıda|kafede|markette|hastanede|parkta|online|telefonda|toplantıda|sınıfta|odada|bahçede)\b/.test(t) },
    { soru: "Ne zaman oldu?", kod: "nezaman", karsilandi: /\b(bugün|dün|sabah|öğlen|akşam|gece|hafta|ay|yıl|saat|geçen|bu sabah|bu hafta|salı|pazartesi|çarşamba|perşembe|cuma|cumartesi|pazar|\d+)\b/.test(t) },
    { soru: "Kim vardı?", kod: "kim", karsilandi: /\b(ben|o|biz|onlar|arkadaş|aile|anne|baba|kardeş|eş|sevgili|müdür|patron|iş arkadaşı|öğretmen|arkadaşım|annem|babam|kardeşim|eşim|sevgilim|müdürüm|kimse|yalnız|tek başıma|hoca|komşu)\b/.test(t) },
  ];
};

// ── API ────────────────────────────────────────────────────────────────────────
const claudeAPI = async (prompt) => {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, messages: [{ role: "user", content: prompt }] }),
  });
  const data = await res.json();
  return data.content?.[0]?.text || "";
};

