// ── Mail ───────────────────────────────────────────────────────────────────────
const mailGonder = async (f) => {
  const tarih = new Date().toLocaleDateString("tr-TR", { weekday: "long", year: "numeric", month: "long", day: "numeric" });
  const form_icerik = `COGNITO PSİKOLOJİ — CBT DÜŞÜNCE KAYIT FORMU
━━━━━━━━━━━━━━━━━━━━━━━━━━
Danışan: ${f.danisanAd}
Psikolog: ${f.psikolog.ad}
Tarih: ${tarih}

📌 OLAY
${f.olay}

💙 DUYGULAR
${f.duygular.map(d => `  • ${d.ad} %${d.yuzde}`).join("\n")}

💬 NEDEN BÖYLE HİSSETTİ
${f.cunku}

⚡ OTOMATİK DÜŞÜNCE (İnanç: %${f.otomatikInanc})
${f.otomatikDusunce}

✅ DESTEKLEYİCİ DELİLLER
${f.kanit}

❌ KARŞIT DELİLLER
${f.aksiKanit}

🌱 GERÇEKÇİ DÜŞÜNCE (İnanç: %${f.gercekciInanc})
${f.gercekciDusunce}

🌟 YENİ DUYGU: ${f.yeniDuygu} (%${f.yeniDuyguYuzde})
━━━━━━━━━━━━━━━━━━━━━━━━━━
Cognito Psikoloji — AI Destekli CBT Formu`;

  return new Promise((resolve) => {
    const xhr = new XMLHttpRequest();
    xhr.open("POST", "https://api.emailjs.com/api/v1.0/email/send", true);
    xhr.setRequestHeader("Content-Type", "application/json");
    xhr.onreadystatechange = () => {
      if (xhr.readyState === 4) {
        console.log("EmailJS XHR status:", xhr.status, xhr.responseText);
        resolve(xhr.status === 200);
      }
    };
    xhr.onerror = () => {
      console.error("XHR network error");
      resolve(false);
    };
    xhr.send(JSON.stringify({
      service_id: "service_we8z4oq",
      template_id: "template_e99vrze",
      user_id: "5OK5wn96I2Uooml44",
      template_params: {
        danisan_ad: f.danisanAd,
        psikologa_mail: f.psikolog.mail,
        name: f.danisanAd,
        form_icerik: form_icerik,
      }
    }));
  });
};

