// ── Olay Adımı ─────────────────────────────────────────────────────────────────
const OlayAdimi = ({ olay, setOlay, ileriGit }) => {
  const sorular = kontrol5N1K(olay);
  const karsilanan = sorular.filter(s => s.karsilandi).length;
  const tamam = karsilanan === sorular.length;
  const mesajlar = ["Olayı biraz daha anlatabilirsin 🌿", "Güzel başlangıç! Nerede ve ne zaman olduğunu ekleyebilirsin.", "İyi gidiyorsun! Kim vardı bilgisini de ekleyebilirsin.", "Neredeyse tamamladın, küçük bir detay daha ekler misin?"];
  return (
    <div style={fc.adim}>
      <div style={fc.etiket}>📌 Olay</div>
      <h2 style={fc.baslik}>Ne oldu?</h2>
      <p style={fc.aciklama}>Olayı kendi kelimelerinle anlatmaya başla, aşağıdaki sorular seni yönlendirecek.</p>
      <textarea style={fc.textarea} rows={4} placeholder="Anlatmaya başla..." value={olay} onChange={e => setOlay(e.target.value)} />
      {olay.trim().length > 0 && (
        <>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
            {sorular.map(s => (
              <div key={s.kod} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", borderRadius: 8, background: s.karsilandi ? "rgba(201,168,76,0.08)" : "rgba(255,255,255,0.02)", border: `1px solid ${s.karsilandi ? "rgba(201,168,76,0.35)" : "rgba(255,255,255,0.06)"}`, transition: "all 0.3s" }}>
                <span>{s.karsilandi ? "✅" : "⭕"}</span>
                <span style={{ fontSize: 12, color: s.karsilandi ? "#C9A84C" : "rgba(201,168,76,0.3)", transition: "color 0.3s" }}>{s.soru}</span>
              </div>
            ))}
          </div>
          <p style={{ fontSize: 12, color: tamam ? "#C9A84C" : "rgba(201,168,76,0.5)", fontStyle: "italic", textAlign: "center" }}>
            {tamam ? "✨ Olayı güzel özetledin, devam edebiliriz." : mesajlar[karsilanan]}
          </p>
        </>
      )}
      <button style={{ ...fc.btn, opacity: olay.trim().length > 10 ? 1 : 0.4 }} disabled={olay.trim().length <= 10} onClick={ileriGit}>Devam →</button>
    </div>
  );
};

// ── Duygu Adımı ────────────────────────────────────────────────────────────────
const DuyguAdimi = ({ duygular, setDuygular, ileriGit }) => {
  const [serbest, setSerbest] = useState("");
  const [serbetYuzde, setSerbetYuzde] = useState(50);
  const [yardimAcik, setYardimAcik] = useState(false);
  const [temelSecim, setTemelSecim] = useState(null);
  const [kompleksSecim, setKompleksSecim] = useState("");
  const [kompleksYuzde, setKompleksYuzde] = useState(50);
  const seciliTemel = TEMEL_DUYGULAR.find(d => d.ad === temelSecim);

  const serbestEkle = () => {
    if (!serbest.trim()) return;
    setDuygular([...duygular, { ad: serbest.trim(), yuzde: serbetYuzde }]);
    setSerbest(""); setSerbetYuzde(50);
  };

  const yardimEkle = () => {
    if (!kompleksSecim) return;
    setDuygular([...duygular, { ad: kompleksSecim, yuzde: kompleksYuzde, temel: temelSecim }]);
    setKompleksSecim(""); setKompleksYuzde(50); setTemelSecim(null); setYardimAcik(false);
  };

  return (
    <div style={fc.adim}>
      <div style={fc.etiket}>💙 Duygu</div>
      <h2 style={fc.baslik}>Bu olayda nasıl hissettin?</h2>
      <p style={fc.aciklama}>Duygunu kendin yazıp derecelendirebilirsin. Birden fazla duygu ekleyebilirsin.</p>

      {duygular.length > 0 && (
        <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          {duygular.map((d, i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "8px 14px", borderRadius: 10, background: "rgba(201,168,76,0.08)", border: "1px solid rgba(201,168,76,0.25)" }}>
              <span style={{ fontSize: 13, color: "#e8d5a3" }}>
                {d.temel && <span style={{ fontSize: 11, color: "rgba(201,168,76,0.5)", marginRight: 6 }}>{d.temel} →</span>}
                {d.ad} <span style={{ color: "#C9A84C", fontWeight: 600 }}>%{d.yuzde}</span>
              </span>
              <button onClick={() => setDuygular(duygular.filter((_, idx) => idx !== i))} style={{ background: "none", border: "none", color: "rgba(201,168,76,0.5)", cursor: "pointer", fontSize: 18, lineHeight: 1 }}>×</button>
            </div>
          ))}
        </div>
      )}

      {!yardimAcik && (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <input style={fc.input} placeholder="Duyguyu yaz (örn. endişeli, hüzünlü, sinirli...)" value={serbest}
            onChange={e => setSerbest(e.target.value)} onKeyDown={e => e.key === "Enter" && serbestEkle()} />
          {serbest.trim() && (
            <>
              <p style={fc.aciklama}>Bu duygunun yoğunluğu?</p>
              <Slider value={serbetYuzde} onChange={setSerbetYuzde} />
              <button style={{ ...fc.btn, background: "rgba(201,168,76,0.12)", color: "#C9A84C", border: "1px solid rgba(201,168,76,0.3)" }} onClick={serbestEkle}>+ Ekle</button>
            </>
          )}
        </div>
      )}

      {!yardimAcik && (
        <button style={{ ...fc.btn, background: "transparent", color: "rgba(201,168,76,0.55)", border: "1px dashed rgba(201,168,76,0.25)", fontSize: 13 }} onClick={() => setYardimAcik(true)}>
          🤔 Tanımlamakta zorlanıyorum, yardım et
        </button>
      )}

      {yardimAcik && (
        <div style={{ display: "flex", flexDirection: "column", gap: 14, padding: 16, background: "rgba(255,255,255,0.02)", borderRadius: 14, border: "1px solid rgba(201,168,76,0.15)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <p style={{ fontSize: 13, color: "#C9A84C", fontWeight: 500 }}>
              {!temelSecim ? "Genel olarak nasıl hissediyorsun?" : `${seciliTemel?.emoji} ${temelSecim} — daha spesifik olarak?`}
            </p>
            <button onClick={() => { setYardimAcik(false); setTemelSecim(null); setKompleksSecim(""); }} style={{ background: "none", border: "none", color: "rgba(201,168,76,0.4)", cursor: "pointer", fontSize: 20 }}>×</button>
          </div>
          {!temelSecim && (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
              {TEMEL_DUYGULAR.map(d => (
                <button key={d.ad} onClick={() => { setTemelSecim(d.ad); setKompleksSecim(""); }}
                  style={{ padding: "14px 6px", borderRadius: 12, border: `1.5px solid ${d.renk}55`, background: "rgba(255,255,255,0.03)", color: "#e8d5a3", cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 6, transition: "all 0.2s" }}>
                  <span style={{ fontSize: 26 }}>{d.emoji}</span>
                  <span style={{ fontSize: 11, color: d.renk, fontWeight: 600 }}>{d.ad}</span>
                </button>
              ))}
            </div>
          )}
          {temelSecim && seciliTemel && (
            <>
              <button onClick={() => { setTemelSecim(null); setKompleksSecim(""); }} style={{ background: "none", border: "none", color: "rgba(201,168,76,0.5)", cursor: "pointer", fontSize: 13, textAlign: "left", padding: 0 }}>← Geri dön</button>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
                {seciliTemel.kompleks.map(k => (
                  <button key={k} onClick={() => setKompleksSecim(k)}
                    style={{ padding: "9px 10px", borderRadius: 8, border: `1px solid ${kompleksSecim === k ? seciliTemel.renk : "rgba(201,168,76,0.15)"}`, background: kompleksSecim === k ? `${seciliTemel.renk}22` : "rgba(255,255,255,0.02)", color: kompleksSecim === k ? "#e8d5a3" : "rgba(201,168,76,0.55)", cursor: "pointer", fontSize: 12, transition: "all 0.2s", textAlign: "center" }}>
                    {k}
                  </button>
                ))}
              </div>
              {kompleksSecim && (
                <>
                  <p style={fc.aciklama}>"{kompleksSecim}" duygusunun yoğunluğu?</p>
                  <Slider value={kompleksYuzde} onChange={setKompleksYuzde} renk={seciliTemel.renk} />
                  <button style={fc.btn} onClick={yardimEkle}>+ Ekle</button>
                </>
              )}
            </>
          )}
        </div>
      )}

      <button style={{ ...fc.btn, opacity: duygular.length > 0 ? 1 : 0.4, marginTop: 4 }} disabled={duygular.length === 0} onClick={ileriGit}>
        Devam →
      </button>
    </div>
  );
};

// ── Çünkü Adımı ────────────────────────────────────────────────────────────────
const CunkuAdimi = ({ olay, duygular, cunku, setCunku, ileriGit }) => {
  const [oneri, setOneri] = useState([]);
  const [yukleniyor, setYukleniyor] = useState(true);
  const [secili, setSecili] = useState("");
  const [kisisel, setKisisel] = useState("");

  useState(() => {
    (async () => {
      try {
        const yanit = await claudeAPI(CUNKU_PROMPT(olay, duygular));
        const clean = yanit.replace(/```json|```/g, "").trim();
        setOneri(JSON.parse(clean).oneri || []);
      } catch {
        setOneri([
          "beklentilerim karşılanmadı",
          "kendimi değersiz hissettim",
          "kontrolümü kaybettiğimi düşündüm",
          "kimse beni anlamıyor gibi geldi",
        ]);
      }
      setYukleniyor(false);
    })();
  }, []);

  const sec = (o) => { setSecili(o); setKisisel(""); setCunku(o); };
  const yazKisisel = (v) => { setKisisel(v); setSecili(""); setCunku(v); };

  return (
    <div style={fc.adim}>
      <div style={fc.etiket}>💬 Neden?</div>
      <h2 style={fc.baslik}>Böyle hissettim çünkü...</h2>
      <p style={fc.aciklama}>Yaşadıklarını ve duygularını göz önüne alarak sana birkaç öneri hazırladım. Birini seçebilir ya da kendin yazabilirsin.</p>

      {yukleniyor ? (
        <div style={fc.yukBox}>
          <div style={fc.spinner} />
          <span style={{ color: "#C9A84C", fontSize: 13 }}>Sana özel öneriler hazırlanıyor...</span>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {oneri.map((o, i) => (
            <button key={i} onClick={() => sec(o)}
              style={{ ...fc.secBtn, background: secili === o ? "rgba(201,168,76,0.15)" : "transparent", borderColor: secili === o ? "#C9A84C" : "rgba(201,168,76,0.2)", textAlign: "left" }}>
              <span style={{ color: "rgba(201,168,76,0.5)", marginRight: 6, fontSize: 12 }}>…</span>{o}
            </button>
          ))}
        </div>
      )}

      <div style={{ marginTop: 4 }}>
        <p style={{ fontSize: 12, color: "rgba(201,168,76,0.5)", marginBottom: 8, fontStyle: "italic" }}>Ya da kendin yaz:</p>
        <textarea style={fc.textarea} rows={2}
          placeholder="kendi ifadenle tamamla..."
          value={kisisel}
          onChange={e => yazKisisel(e.target.value)}
        />
      </div>

      <button style={{ ...fc.btn, opacity: cunku.trim() ? 1 : 0.4 }} disabled={!cunku.trim()} onClick={ileriGit}>
        Devam →
      </button>
    </div>
  );
};


// ── Yeni Duygu Adımı (Gerçekçi düşünce sonrası - çember ile) ──────────────────
const YeniDuyguAdimi = ({ gercekciDusunce, yeniDuygu, setYeniDuygu, yeniDuyguYuzde, setYeniDuyguYuzde, ileriGit }) => {
  const [yardimAcik, setYardimAcik] = useState(false);
  const [temelSecim, setTemelSecim] = useState(null);
  const [kompleksSecim, setKompleksSecim] = useState("");
  const [kompleksYuzde, setKompleksYuzde] = useState(50);
  const [serbest, setSerbest] = useState("");
  const [serbetYuzde, setSerbetYuzde] = useState(50);
  const seciliTemel = TEMEL_DUYGULAR.find(d => d.ad === temelSecim);

  const serbestEkle = () => {
    if (!serbest.trim()) return;
    setYeniDuygu(serbest.trim());
    setYeniDuyguYuzde(serbetYuzde);
    setSerbest("");
  };

  const yardimSec = () => {
    if (!kompleksSecim) return;
    setYeniDuygu(kompleksSecim);
    setYeniDuyguYuzde(kompleksYuzde);
    setYardimAcik(false); setTemelSecim(null); setKompleksSecim("");
  };

  return (
    <div style={fc.adim}>
      <div style={fc.etiket}>🌟 Yeni Duygu</div>
      <h2 style={fc.baslik}>Şimdi nasıl hissediyorsun?</h2>

      {/* Gerçekçi düşünce hatırlatması */}
      <div style={{ padding: "10px 14px", background: "rgba(201,168,76,0.06)", borderRadius: 10, border: "1px solid rgba(201,168,76,0.15)" }}>
        <p style={{ fontSize: 11, color: "#C9A84C", letterSpacing: 1, marginBottom: 6 }}>🌱 GERÇEKÇİ DÜŞÜNCENİ HATIRLA</p>
        <p style={{ fontSize: 13, color: "#b09060", lineHeight: 1.6, fontStyle: "italic" }}>{gercekciDusunce}</p>
      </div>

      <p style={{ fontSize: 14, color: "#d4b97a", fontWeight: 500, lineHeight: 1.6 }}>
        Bu gerçekçi düşünce cümlesine odaklandığında, bu sana nasıl hissettiriyor?
      </p>

      {/* Seçilen duygu göster */}
      {yeniDuygu && (
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 14px", borderRadius: 10, background: "rgba(201,168,76,0.08)", border: "1px solid rgba(201,168,76,0.25)" }}>
          <span style={{ fontSize: 13, color: "#e8d5a3" }}>
            {yeniDuygu} <span style={{ color: "#C9A84C", fontWeight: 600 }}>%{yeniDuyguYuzde}</span>
          </span>
          <button onClick={() => { setYeniDuygu(""); setYeniDuyguYuzde(50); }} style={{ background: "none", border: "none", color: "rgba(201,168,76,0.5)", cursor: "pointer", fontSize: 18 }}>×</button>
        </div>
      )}

      {/* Serbest yazım */}
      {!yardimAcik && !yeniDuygu && (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <input style={fc.input} placeholder="Duyguyu yaz (örn. umutlu, sakin, rahatlamış...)"
            value={serbest} onChange={e => setSerbest(e.target.value)} onKeyDown={e => e.key === "Enter" && serbestEkle()} />
          {serbest.trim() && (
            <>
              <p style={fc.aciklama}>Yoğunluğu?</p>
              <Slider value={serbetYuzde} onChange={setSerbetYuzde} />
              <button style={{ ...fc.btn, background: "rgba(201,168,76,0.12)", color: "#C9A84C", border: "1px solid rgba(201,168,76,0.3)" }} onClick={serbestEkle}>+ Ekle</button>
            </>
          )}
        </div>
      )}

      {/* Yardım butonu */}
      {!yardimAcik && !yeniDuygu && (
        <button style={{ ...fc.btn, background: "transparent", color: "rgba(201,168,76,0.55)", border: "1px dashed rgba(201,168,76,0.25)", fontSize: 13 }} onClick={() => setYardimAcik(true)}>
          🤔 Tanımlamakta zorlanıyorum, yardım et
        </button>
      )}

      {/* Duygu çemberi paneli */}
      {yardimAcik && (
        <div style={{ display: "flex", flexDirection: "column", gap: 14, padding: 16, background: "rgba(255,255,255,0.02)", borderRadius: 14, border: "1px solid rgba(201,168,76,0.15)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <p style={{ fontSize: 13, color: "#C9A84C", fontWeight: 500 }}>
              {!temelSecim ? "Genel olarak nasıl hissediyorsun?" : `${seciliTemel?.emoji} ${temelSecim} — daha spesifik olarak?`}
            </p>
            <button onClick={() => { setYardimAcik(false); setTemelSecim(null); setKompleksSecim(""); }} style={{ background: "none", border: "none", color: "rgba(201,168,76,0.4)", cursor: "pointer", fontSize: 20 }}>×</button>
          </div>
          {!temelSecim && (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
              {TEMEL_DUYGULAR.map(d => (
                <button key={d.ad} onClick={() => { setTemelSecim(d.ad); setKompleksSecim(""); }}
                  style={{ padding: "14px 6px", borderRadius: 12, border: `1.5px solid ${d.renk}55`, background: "rgba(255,255,255,0.03)", color: "#e8d5a3", cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 6, transition: "all 0.2s" }}>
                  <span style={{ fontSize: 26 }}>{d.emoji}</span>
                  <span style={{ fontSize: 11, color: d.renk, fontWeight: 600 }}>{d.ad}</span>
                </button>
              ))}
            </div>
          )}
          {temelSecim && seciliTemel && (
            <>
              <button onClick={() => { setTemelSecim(null); setKompleksSecim(""); }} style={{ background: "none", border: "none", color: "rgba(201,168,76,0.5)", cursor: "pointer", fontSize: 13, textAlign: "left", padding: 0 }}>← Geri dön</button>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
                {seciliTemel.kompleks.map(k => (
                  <button key={k} onClick={() => setKompleksSecim(k)}
                    style={{ padding: "9px 10px", borderRadius: 8, border: `1px solid ${kompleksSecim === k ? seciliTemel.renk : "rgba(201,168,76,0.15)"}`, background: kompleksSecim === k ? `${seciliTemel.renk}22` : "rgba(255,255,255,0.02)", color: kompleksSecim === k ? "#e8d5a3" : "rgba(201,168,76,0.55)", cursor: "pointer", fontSize: 12, transition: "all 0.2s", textAlign: "center" }}>
                    {k}
                  </button>
                ))}
              </div>
              {kompleksSecim && (
                <>
                  <p style={fc.aciklama}>"{kompleksSecim}" duygusunun yoğunluğu?</p>
                  <Slider value={kompleksYuzde} onChange={setKompleksYuzde} renk={seciliTemel.renk} />
                  <button style={fc.btn} onClick={yardimSec}>+ Seç</button>
                </>
              )}
            </>
          )}
        </div>
      )}

      <button style={{ ...fc.btn, opacity: yeniDuygu ? 1 : 0.4 }} disabled={!yeniDuygu} onClick={ileriGit}>
        Özeti Gör →
      </button>
    </div>
  );
};

// ── Ana Bileşen ────────────────────────────────────────────────────────────────
export default function CognitoCBT() {
  const [adim, setAdim] = useState(0);
  const [danisanAd, setDanisanAd] = useState("");
  const [seciliPsikolog, setSeciliPsikolog] = useState(null);
  const [mailGonderiliyor, setMailGonderiliyor] = useState(false);
  const [mailHata, setMailHata] = useState(false);

  useEffect(() => {
    if (window.emailjs) {
      window.emailjs.init("5OK5wn96I2Uooml44");
      return;
    }
    const script = document.createElement("script");
    script.src = "https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js";
    script.async = true;
    script.onload = () => {
      window.emailjs.init("5OK5wn96I2Uooml44");
      console.log("EmailJS yüklendi ✓");
    };
    script.onerror = () => console.error("EmailJS yüklenemedi!");
    document.head.appendChild(script);
  }, []);
  const [olay, setOlay] = useState("");
  const [duygular, setDuygular] = useState([]);
  const [cunku, setCunku] = useState("");
  const [otoDusunceler, setOtoDusunceler] = useState([]);
  const [seciliOto, setSeciliOto] = useState("");
  const [kisiselOto, setKisiselOto] = useState("");
  const [otomatikInanc, setOtomatikInanc] = useState(70);
  const [kanit, setKanit] = useState("");
  const [aksiKanit, setAksiKanit] = useState("");
  const [gercekciDusunce, setGercekciDusunce] = useState("");
  const [gercekciInanc, setGercekciInanc] = useState(50);
  const [yeniDuygu, setYeniDuygu] = useState("");
  const [yeniDuyguYuzde, setYeniDuyguYuzde] = useState(50);
  const [yukleniyor, setYukleniyor] = useState(false);
  const [gonderildi, setGonderildi] = useState(false);

  // adım sırası: 0=karşılama 1=olay 2=duygu 3=çünkü 4=oto-düşünce 5=kanıt 6=aksi 7=gerçekçi 8=yeni-duygu 9=özet
  const TOPLAM = 8;

  const otoDusunceGetir = async () => {
    setYukleniyor(true);
    try {
      const yanit = await claudeAPI(OTO_PROMPT(olay, duygular, cunku));
      const clean = yanit.replace(/```json|```/g, "").trim();
      setOtoDusunceler(JSON.parse(clean).dusunceler || []);
    } catch {
      setOtoDusunceler(["Bu durumla başa çıkamam.", "Her şey benim hatam.", "Hiçbir şey değişmeyecek.", "Kimse beni anlamıyor."]);
    }
    setYukleniyor(false);
  };

  const ileriGit = async () => {
    if (adim === 1 && olay.trim().length > 10) setAdim(2);
    else if (adim === 2 && duygular.length > 0) setAdim(3);
    else if (adim === 3 && cunku.trim()) { setAdim(4); await otoDusunceGetir(); }
    else if (adim === 4 && (seciliOto || kisiselOto.trim())) setAdim(5);
    else if (adim === 5 && kanit.trim()) setAdim(6);
    else if (adim === 6 && aksiKanit.trim()) setAdim(7);
    else if (adim === 7) setAdim(8);
    else if (adim === 8 && yeniDuygu.trim()) setAdim(9);
  };

  const sifirla = () => {
    setAdim(0); setDanisanAd(""); setOlay(""); setDuygular([]); setCunku(""); setSeciliPsikolog(null); setMailHata(false);
    setSeciliOto(""); setKisiselOto(""); setKanit(""); setAksiKanit("");
    setGercekciDusunce(""); setYeniDuygu(""); setGonderildi(false);
  };

  return (
    <div style={gs.root}>
      <div style={gs.bgGrad} />
      <div style={gs.wrapper}>

        <div style={gs.logoBar}>
          <div style={gs.logoText}>COGNITO</div>
          <div style={gs.logoDivider} />
          <div style={gs.logoSub}>Psikoloji</div>
        </div>

        {adim > 0 && adim < 10 && <AdimGostergesi aktif={adim - 1} toplam={TOPLAM} />}

        <div style={gs.kart}>

          {/* 0 — Psikolog Seçimi + Karşılama */}
          {adim === 0 && (
            <div style={fc.adim}>
              <div style={{ fontSize: 48, textAlign: "center" }}>🧠</div>
              <h2 style={fc.baslik}>Düşünce Kayıt Formu</h2>
              <p style={fc.aciklama}>Bu form, yaşadığın bir olayı CBT perspektifiyle incelemene ve gerçekçi düşünceler geliştirmene yardımcı olacak.</p>

              <p style={{ fontSize: 13, color: "#C9A84C", fontWeight: 500, marginTop: 4 }}>Psikologunuzu seçin</p>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                {PSIKOLOGLAR.map((p, i) => (
                  <button key={i} onClick={() => setSeciliPsikolog(p)}
                    style={{
                      display: "flex", flexDirection: "column", alignItems: "center", gap: 10,
                      padding: "16px 10px", borderRadius: 16, cursor: "pointer",
                      border: `1.5px solid ${seciliPsikolog?.mail === p.mail ? "#C9A84C" : "rgba(201,168,76,0.2)"}`,
                      background: seciliPsikolog?.mail === p.mail ? "rgba(201,168,76,0.1)" : "rgba(255,255,255,0.02)",
                      transition: "all 0.2s",
                    }}>
                    <div style={{ width: 80, height: 80, borderRadius: "50%", overflow: "hidden", border: `2px solid ${seciliPsikolog?.mail === p.mail ? "#C9A84C" : "rgba(201,168,76,0.3)"}` }}>
                      <img src={p.foto} alt={p.kisa} style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center top" }} />
                    </div>
                    <span style={{ fontSize: 11, color: seciliPsikolog?.mail === p.mail ? "#C9A84C" : "#b09060", textAlign: "center", lineHeight: 1.4, fontWeight: seciliPsikolog?.mail === p.mail ? 600 : 400 }}>{p.ad}</span>
                  </button>
                ))}
              </div>

              <input style={fc.input} placeholder="Adın ve soyadın" value={danisanAd} onChange={e => setDanisanAd(e.target.value)} />
              <button
                style={{ ...fc.btn, opacity: (danisanAd.trim() && seciliPsikolog) ? 1 : 0.4 }}
                disabled={!danisanAd.trim() || !seciliPsikolog}
                onClick={() => setAdim(1)}
              >
                Başla →
              </button>
            </div>
          )}

          {/* 1 — Olay */}
          {adim === 1 && <OlayAdimi olay={olay} setOlay={setOlay} ileriGit={ileriGit} />}

          {/* 2 — Duygu */}
          {adim === 2 && <DuyguAdimi duygular={duygular} setDuygular={setDuygular} ileriGit={ileriGit} />}

          {/* 3 — Çünkü */}
          {adim === 3 && <CunkuAdimi olay={olay} duygular={duygular} cunku={cunku} setCunku={setCunku} ileriGit={ileriGit} />}

          {/* 4 — Otomatik Düşünce */}
          {adim === 4 && (
            <div style={fc.adim}>
              <div style={fc.etiket}>⚡ Otomatik Düşünce</div>
              <h2 style={fc.baslik}>Aklına gelen ilk düşünce?</h2>
              <p style={fc.aciklama}>Olayı yaşarken aklına gelen düşünceyi seç veya kendin yaz.</p>
              {yukleniyor ? (
                <div style={fc.yukBox}><div style={fc.spinner} /><span style={{ color: "#C9A84C", fontSize: 13 }}>Olası düşünceler analiz ediliyor...</span></div>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 8 }}>
                  {otoDusunceler.map((d, i) => (
                    <button key={i} onClick={() => { setSeciliOto(d); setKisiselOto(""); }}
                      style={{ ...fc.secBtn, background: seciliOto === d ? "rgba(201,168,76,0.15)" : "transparent", borderColor: seciliOto === d ? "#C9A84C" : "rgba(201,168,76,0.2)" }}>
                      {d}
                    </button>
                  ))}
                </div>
              )}
              <p style={{ fontSize: 12, color: "rgba(201,168,76,0.5)", marginBottom: 8, fontStyle: "italic" }}>Ya da kendin yaz:</p>
              <textarea style={fc.textarea} rows={2} placeholder="Kendi düşünceni buraya yaz..." value={kisiselOto} onChange={e => { setKisiselOto(e.target.value); setSeciliOto(""); }} />
              {(seciliOto || kisiselOto.trim()) && (
                <><p style={fc.aciklama}>Bu düşünceye ne kadar inanıyorsun?</p><Slider value={otomatikInanc} onChange={setOtomatikInanc} /></>
              )}
              <button style={{ ...fc.btn, opacity: (seciliOto || kisiselOto.trim()) ? 1 : 0.4 }} disabled={!seciliOto && !kisiselOto.trim()} onClick={ileriGit}>Devam →</button>
            </div>
          )}

          {/* 5 — Kanıt */}
          {adim === 5 && (
            <div style={fc.adim}>
              <div style={fc.etiket}>✅ Kanıt</div>
              <h2 style={fc.baslik}>Bu düşünceyi destekleyen gerçekler?</h2>
              <div style={fc.ozet}><span style={{ color: "#C9A84C", fontSize: 12 }}>⚡ Düşüncen:</span><p style={{ color: "#e8d5a3", fontSize: 13, marginTop: 4 }}>{seciliOto || kisiselOto}</p></div>
              <p style={{ fontSize: 14, color: "#d4b97a", fontWeight: 500, lineHeight: 1.6 }}>Bu düşüncenin doğru olduğuna seni en çok ikna eden somut olaylar neler?</p>
              <textarea style={fc.textarea} rows={4} placeholder="Yaşananları somut olarak anlat..." value={kanit} onChange={e => setKanit(e.target.value)} />
              <div style={{ display: "flex", gap: 8, padding: "10px 14px", background: "rgba(255,255,255,0.02)", borderRadius: 10, border: "1px solid rgba(201,168,76,0.12)", alignItems: "flex-start" }}>
                <span style={{ fontSize: 14, flexShrink: 0 }}>💡</span>
                <p style={{ fontSize: 12, color: "rgba(201,168,76,0.5)", lineHeight: 1.6, fontStyle: "italic" }}>Burada hislerini değil, kanıtlanabilir somut gözlemleri ve gerçekleri yazman önemli.</p>
              </div>
              <button style={{ ...fc.btn, opacity: kanit.trim() ? 1 : 0.4 }} disabled={!kanit.trim()} onClick={ileriGit}>Devam →</button>
            </div>
          )}

          {/* 6 — Aksi Kanıt */}
          {adim === 6 && (
            <div style={fc.adim}>
              <div style={fc.etiket}>❌ Aksi Kanıt</div>
              <h2 style={fc.baslik}>Bu düşünceye karşı deliller?</h2>
              <div style={fc.ozet}><span style={{ color: "#C9A84C", fontSize: 12 }}>⚡ Düşüncen:</span><p style={{ color: "#e8d5a3", fontSize: 13, marginTop: 4 }}>{seciliOto || kisiselOto}</p></div>
              <p style={{ fontSize: 14, color: "#d4b97a", fontWeight: 500, lineHeight: 1.6 }}>Daha önce bunun aksini yaşadığın bir an oldu mu?</p>
              <textarea style={fc.textarea} rows={4} placeholder="Somut bir anı veya gözlemi yaz..." value={aksiKanit} onChange={e => setAksiKanit(e.target.value)} />
              <div style={{ display: "flex", gap: 8, padding: "10px 14px", background: "rgba(255,255,255,0.02)", borderRadius: 10, border: "1px solid rgba(201,168,76,0.12)", alignItems: "flex-start" }}>
                <span style={{ fontSize: 14, flexShrink: 0 }}>💡</span>
                <p style={{ fontSize: 12, color: "rgba(201,168,76,0.5)", lineHeight: 1.6, fontStyle: "italic" }}>Burada hislerini değil, kanıtlanabilir somut gözlemleri ve gerçekleri yazman önemli.</p>
              </div>
              <button style={{ ...fc.btn, opacity: aksiKanit.trim() ? 1 : 0.4 }} disabled={!aksiKanit.trim()} onClick={ileriGit}>Devam →</button>
            </div>
          )}

          {/* 7 — Gerçekçi Düşünce */}
          {adim === 7 && (
            <div style={fc.adim}>
              <div style={fc.etiket}>🌱 Gerçekçi Düşünce</div>
              <h2 style={fc.baslik}>Şimdi dengeli bir bakış açısı oluştur</h2>

              {/* Kanıtlar özeti */}
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                <div style={{ padding: "10px 14px", background: "rgba(201,168,76,0.06)", borderRadius: 10, border: "1px solid rgba(201,168,76,0.15)" }}>
                  <p style={{ fontSize: 11, color: "#C9A84C", letterSpacing: 1, marginBottom: 6 }}>✅ DESTEKLEYİCİ DELİLLER</p>
                  <p style={{ fontSize: 13, color: "#b09060", lineHeight: 1.6 }}>{kanit}</p>
                </div>
                <div style={{ padding: "10px 14px", background: "rgba(155,137,180,0.06)", borderRadius: 10, border: "1px solid rgba(155,137,180,0.2)" }}>
                  <p style={{ fontSize: 11, color: "#9B89B4", letterSpacing: 1, marginBottom: 6 }}>❌ KARŞIT DELİLLER</p>
                  <p style={{ fontSize: 13, color: "#b09060", lineHeight: 1.6 }}>{aksiKanit}</p>
                </div>
              </div>

              <p style={{ fontSize: 14, color: "#d4b97a", fontWeight: 500, lineHeight: 1.7 }}>
                Tüm kanıtları birlikte düşündüğümüzde, bu duruma en dengeli nasıl bakabiliriz?
              </p>

              <textarea
                style={fc.textarea} rows={4}
                placeholder="Gerçekçi düşünceni buraya yaz..."
                value={gercekciDusunce}
                onChange={e => setGercekciDusunce(e.target.value)}
              />

              {gercekciDusunce.trim() && (
                <>
                  <p style={fc.aciklama}>Bu düşünceye ne kadar inanıyorsun?</p>
                  <Slider value={gercekciInanc} onChange={setGercekciInanc} />
                </>
              )}

              <button style={{ ...fc.btn, opacity: gercekciDusunce.trim() ? 1 : 0.4 }} disabled={!gercekciDusunce.trim()} onClick={ileriGit}>Devam →</button>
            </div>
          )}

          {/* 8 — Yeni Duygu */}
          {adim === 8 && (
            <YeniDuyguAdimi
              gercekciDusunce={gercekciDusunce}
              yeniDuygu={yeniDuygu}
              setYeniDuygu={setYeniDuygu}
              yeniDuyguYuzde={yeniDuyguYuzde}
              setYeniDuyguYuzde={setYeniDuyguYuzde}
              ileriGit={ileriGit}
            />
          )}

          {/* 9 — Özet */}
          {adim === 9 && !gonderildi && (
            <div style={fc.adim}>
              <div style={{ fontSize: 48, textAlign: "center" }}>✨</div>
              <h2 style={fc.baslik}>Tebrikler, {danisanAd.split(" ")[0]}!</h2>
              <p style={fc.aciklama}>Düşünce kaydını tamamladın. Özet psikologuna gönderilmeye hazır.</p>
              <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 8 }}>
                {[
                  { e: "📌", k: "Olay", v: olay },
                  { e: "💙", k: "Duygular", v: duygular.map(d => `${d.ad} %${d.yuzde}`).join(", ") },
                  { e: "💬", k: "Neden", v: cunku },
                  { e: "⚡", k: "Oto. Düşünce", v: (seciliOto || kisiselOto).substring(0, 60) + "..." },
                  { e: "🌱", k: "Yeni Düşünce", v: gercekciDusunce.substring(0, 80) + "..." },
                  { e: "🌟", k: "Yeni Duygu", v: `${yeniDuygu} %${yeniDuyguYuzde}` },
                ].map((r, i) => (
                  <div key={i} style={{ display: "flex", gap: 10, alignItems: "flex-start", borderBottom: "1px solid rgba(201,168,76,0.08)", paddingBottom: 10 }}>
                    <span style={{ fontSize: 11, color: "#C9A84C", minWidth: 100, flexShrink: 0, paddingTop: 2 }}>{r.e} {r.k}</span>
                    <span style={{ fontSize: 13, color: "#b09060", lineHeight: 1.5 }}>{r.v}</span>
                  </div>
                ))}
              </div>
              <button style={{ ...fc.btn, background: "linear-gradient(135deg, #C9A84C, #a07828)" }}
                onClick={async () => {
                  setMailGonderiliyor(true);
                  const basari = await mailGonder({ danisanAd, psikolog: seciliPsikolog, olay, duygular, cunku, otomatikDusunce: seciliOto || kisiselOto, otomatikInanc, kanit, aksiKanit, gercekciDusunce, gercekciInanc, yeniDuygu, yeniDuyguYuzde });
                  setMailGonderiliyor(false);
                  if (basari) setGonderildi(true);
                  else setMailHata(true);
                }}>
                {mailGonderiliyor ? "Gönderiliyor..." : `📧 ${seciliPsikolog?.kisa || "Psikolog"}'a Gönder`}
              </button>
            </div>
          )}

          {/* Mail Hatası */}
          {mailHata && !gonderildi && (
            <div style={{ marginTop: 12, padding: "14px", background: "rgba(192,103,90,0.08)", borderRadius: 12, border: "1px solid rgba(192,103,90,0.3)", display: "flex", flexDirection: "column", gap: 10 }}>
              <p style={{ fontSize: 13, color: "#C0675A", lineHeight: 1.6 }}>⚠️ Mail gönderilemedi. Lütfen sayfayı yenileyip tekrar deneyin ya da aşağıdaki butona bas.</p>
              <button style={{ padding: "10px", borderRadius: 8, background: "rgba(192,103,90,0.15)", border: "1px solid rgba(192,103,90,0.4)", color: "#C0675A", fontSize: 13, cursor: "pointer", fontFamily: "'Jost', sans-serif" }}
                onClick={async () => {
                  setMailHata(false);
                  setMailGonderiliyor(true);
                  const basari = await mailGonder({ danisanAd, psikolog: seciliPsikolog, olay, duygular, cunku, otomatikDusunce: seciliOto || kisiselOto, otomatikInanc, kanit, aksiKanit, gercekciDusunce, gercekciInanc, yeniDuygu, yeniDuyguYuzde });
                  setMailGonderiliyor(false);
                  if (basari) setGonderildi(true);
                  else setMailHata(true);
                }}>
                🔄 Tekrar Dene
              </button>
            </div>
          )}

          {/* Gönderildi */}
          {gonderildi && (
            <div style={{ ...fc.adim, textAlign: "center" }}>
              <div style={{ fontSize: 48 }}>💌</div>
              <h2 style={fc.baslik}>Gönderildi!</h2>
              <p style={fc.aciklama}>{seciliPsikolog?.ad}'e iletildi. Kendine iyi bak. 🌿</p>
              <button style={{ ...fc.btn, background: "rgba(201,168,76,0.1)", color: "#C9A84C", border: "1px solid rgba(201,168,76,0.3)" }} onClick={sifirla}>Yeni Form →</button>
            </div>
          )}

        </div>
        <p style={gs.altYazi}>Cognito Psikoloji © 2025 — Bu form profesyonel terapi yerine geçmez</p>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;1,400&family=Jost:wght@300;400;500&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        textarea, input { outline: none; }
        textarea:focus, input:focus { border-color: rgba(201,168,76,0.6) !important; }
        input[type=range] { -webkit-appearance: none; appearance: none; background: rgba(201,168,76,0.2); border-radius: 4px; }
        input[type=range]::-webkit-slider-thumb { -webkit-appearance: none; width: 18px; height: 18px; border-radius: 50%; cursor: pointer; }
        @keyframes spin { to { transform: rotate(360deg); } }
      `}</style>
    </div>
  );
}

